import { act, render, screen, waitFor } from '@testing-library/react';
import { useSyncExternalStore } from 'react';
import { afterEach, beforeAll, describe, expect, it, vi } from 'vitest';
import { getEffectRegistry, replaceEffectRegistry } from '@/tools/video-editor/effects';
import type { EffectComponentProps } from '@/tools/video-editor/effects/entrances';
import { DynamicEffectRegistry } from '@/tools/video-editor/effects/DynamicEffectRegistry';
import { EffectErrorBoundary } from '@/tools/video-editor/effects/EffectErrorBoundary';
import { preloadSucrase } from '@/tools/video-editor/effects/compileEffect';
import { validateAndCoerceParams } from '@/tools/video-editor/effects/validateParams';
import { useEffectRegistry } from '@/tools/video-editor/hooks/useEffectRegistry';
import type { EffectResource } from '@/tools/video-editor/hooks/useEffectResources';
import type { ParameterSchema } from '@/tools/video-editor/types';

function BuiltInFade(_props: EffectComponentProps) {
  return <div data-testid="builtin-fade" />;
}

const EFFECT_CODE = 'export default function Effect(){ return <div data-testid="dynamic-effect" />; }';

describe('DynamicEffectRegistry', () => {
  beforeAll(async () => {
    await preloadSucrase();
  });

  afterEach(() => {
    localStorage.clear();
    replaceEffectRegistry(new DynamicEffectRegistry({}));
    vi.restoreAllMocks();
  });

  it('prefers built-in effects over dynamic name collisions and resolves custom prefix lookups', async () => {
    const registry = new DynamicEffectRegistry({ fade: BuiltInFade });
    registry.register('fade', 'export default function Effect(){ return <div data-testid="dynamic-fade" />; }');
    await registry.registerAsync('test', 'export default function Effect(){ return <div data-testid="custom-test" />; }');

    const FadeComponent = registry.get('fade');
    const CustomComponent = registry.get('custom:test');

    expect(FadeComponent).toBe(BuiltInFade);
    expect(CustomComponent).toBeDefined();
    expect(registry.getCode('custom:test')).toContain('custom-test');
  });

  it('returns a compile error overlay instead of throwing for invalid custom code', async () => {
    const registry = new DynamicEffectRegistry({});
    expect(() => registry.register('broken', 'export default function Effect( {')).not.toThrow();
    expect(registry.get('broken')).toBeDefined();
  });

  it('tracks subscriptions, deduplicates unchanged registrations, batches notifications, and stores schemas', async () => {
    const schema: ParameterSchema = [
      { name: 'amount', label: 'Amount', description: 'Adjust amount', type: 'number', default: 2, min: 0, max: 5 },
    ];
    const registry = new DynamicEffectRegistry({});
    const listener = vi.fn();
    const unsubscribe = registry.subscribe(listener);

    expect(registry.getSnapshot()).toBe(0);

    registry.register('alpha', EFFECT_CODE);
    expect(listener).toHaveBeenCalledTimes(1);
    expect(registry.getSnapshot()).toBe(1);

    registry.register('alpha', EFFECT_CODE);
    expect(listener).toHaveBeenCalledTimes(1);
    expect(registry.getSnapshot()).toBe(1);

    await registry.batch(async () => {
      registry.register('beta', EFFECT_CODE.replace('dynamic-effect', 'beta-effect'));
      registry.register('gamma', EFFECT_CODE.replace('dynamic-effect', 'gamma-effect'), schema);
    });

    unsubscribe();

    expect(listener).toHaveBeenCalledTimes(2);
    expect(registry.getSnapshot()).toBe(2);
    expect(registry.getSchema('custom:gamma')).toEqual(schema);
  });

  it('renders the fallback when an effect throws inside the boundary', () => {
    const errorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
    const ThrowingEffect = () => {
      throw new Error('boom');
    };

    render(
      <EffectErrorBoundary effectName="explode" fallback={<div data-testid="effect-fallback" />}>
        <ThrowingEffect />
      </EffectErrorBoundary>,
    );

    expect(screen.getByTestId('effect-fallback')).toBeInTheDocument();
    expect(errorSpy).toHaveBeenCalledWith('[EffectErrorBoundary] "explode" runtime error: boom');
    errorSpy.mockRestore();
  });

  it('re-renders subscribed components when async registration completes', async () => {
    const registry = new DynamicEffectRegistry({});

    function RegistryConsumer() {
      const version = useSyncExternalStore(registry.subscribe, registry.getSnapshot);
      const effect = registry.get('async-test');
      return (
        <div data-testid="consumer">
          v{version}:{effect ? 'found' : 'missing'}
        </div>
      );
    }

    render(<RegistryConsumer />);
    expect(screen.getByTestId('consumer').textContent).toBe('v0:missing');

    await act(async () => {
      await registry.registerAsync('async-test', EFFECT_CODE);
    });

    expect(screen.getByTestId('consumer').textContent).toBe('v1:found');
  });

  it('installs the provider registry before child render and re-renders the tree after async registration', async () => {
    vi.spyOn(console, 'warn').mockImplementation(() => {});

    const resourceEffects: EffectResource[] = [
      {
        id: 'resource-effect',
        type: 'effect',
        name: 'Resource Effect',
        slug: 'resource-effect',
        code: EFFECT_CODE,
        category: 'continuous',
        description: 'Async resource effect',
        created_by: { is_you: true },
        is_public: false,
      },
    ];

    function LookupConsumer({ registry }: { registry: DynamicEffectRegistry }) {
      const currentRegistry = getEffectRegistry();
      const effect = currentRegistry.get('custom:resource-effect');
      return (
        <div data-testid="registry-state">
          {currentRegistry === registry ? 'same' : 'different'}:{effect ? 'found' : 'missing'}
        </div>
      );
    }

    function RegistryHost() {
      const registry = useEffectRegistry(undefined, resourceEffects);
      return <LookupConsumer registry={registry} />;
    }

    replaceEffectRegistry(new DynamicEffectRegistry({}));
    render(<RegistryHost />);

    expect(screen.getByTestId('registry-state').textContent).toBe('same:missing');

    await waitFor(() => {
      expect(screen.getByTestId('registry-state').textContent).toBe('same:found');
    });
  });

  it('validates and coerces effect params from schema defaults', () => {
    const schema: ParameterSchema = [
      { name: 'size', label: 'Size', description: 'Effect size', type: 'number', default: 2, min: 0, max: 5 },
      { name: 'opacity', label: 'Opacity', description: 'Effect opacity', type: 'number', default: 0.5, min: 0, max: 1 },
      { name: 'enabled', label: 'Enabled', description: 'Enable effect', type: 'boolean', default: false },
      {
        name: 'mode',
        label: 'Mode',
        description: 'Effect mode',
        type: 'select',
        options: [
          { label: 'Soft', value: 'soft' },
          { label: 'Hard', value: 'hard' },
        ],
      },
      { name: 'color', label: 'Color', description: 'Tint color', type: 'color', default: '#123abc' },
    ];

    expect(validateAndCoerceParams({
      size: '3',
      opacity: 9,
      enabled: 'true',
      mode: 'missing',
      color: 'blue',
    }, schema)).toEqual({
      size: 2,
      opacity: 1,
      enabled: false,
      mode: 'soft',
      color: '#123abc',
    });
  });
});

import { Component, type ReactNode } from 'react';

type EffectErrorBoundaryProps = { effectName: string; fallback: ReactNode; children: ReactNode };
type EffectErrorBoundaryState = { hasError: boolean };

export class EffectErrorBoundary extends Component<EffectErrorBoundaryProps, EffectErrorBoundaryState> {
  state: EffectErrorBoundaryState = { hasError: false };

  static getDerivedStateFromError(): EffectErrorBoundaryState {
    return { hasError: true };
  }

  componentDidCatch(error: Error) {
    console.error(`[EffectErrorBoundary] "${this.props.effectName}" runtime error: ${error.message}`);
  }

  componentDidUpdate(prevProps: EffectErrorBoundaryProps) {
    if (this.state.hasError && prevProps.effectName !== this.props.effectName) this.setState({ hasError: false });
  }

  render() {
    return this.state.hasError ? this.props.fallback : this.props.children;
  }
}

import type { ParameterDefinition, ParameterSchema } from '@/tools/video-editor/types';

const COLOR_RE = /^#[0-9a-f]{3,8}$/i;

const getFallbackValue = (parameter: ParameterDefinition): number | string | boolean => {
  if (parameter.default !== undefined) return parameter.default;
  if (parameter.type === 'number') return parameter.min ?? 0;
  if (parameter.type === 'select') return parameter.options?.[0]?.value ?? '';
  if (parameter.type === 'boolean') return false;
  if (parameter.type === 'color') return '#000000';
  return '';
};

export function validateAndCoerceParams(
  params: Record<string, unknown> | undefined,
  schema: ParameterSchema | undefined,
): Record<string, unknown> {
  if (!schema?.length) return params ?? {};
  return schema.reduce<Record<string, unknown>>((result, parameter) => {
    const fallback = getFallbackValue(parameter);
    const value = params?.[parameter.name];
    if (parameter.type === 'number') {
      result[parameter.name] = typeof value === 'number' && Number.isFinite(value)
        ? Math.min(parameter.max ?? value, Math.max(parameter.min ?? value, value))
        : fallback;
    } else if (parameter.type === 'boolean') {
      result[parameter.name] = typeof value === 'boolean' ? value : fallback;
    } else if (parameter.type === 'select') {
      result[parameter.name] = typeof value === 'string' && (parameter.options ?? []).some((option) => option.value === value) ? value : fallback;
    } else {
      result[parameter.name] = typeof value === 'string' && COLOR_RE.test(value) ? value : fallback;
    }
    return result;
  }, {});
}

import type { FC, ReactNode } from 'react';
import { AbsoluteFill, interpolate, spring, useCurrentFrame, useVideoConfig } from 'remotion';

export type EffectComponentProps = {
  children: ReactNode;
  durationInFrames: number;
  effectFrames?: number;
  intensity?: number;
  params?: Record<string, unknown>;
};

const getNormalizedProgress = (frame: number, durationInFrames: number): number => {
  return interpolate(frame, [0, Math.max(1, durationInFrames)], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
};

const withTransform = (transform: string, opacity = 1): React.CSSProperties => ({
  width: '100%',
  height: '100%',
  transform,
  opacity,
});

export const SlideUpEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const progress = spring({ frame, fps, durationInFrames: effectFrames, config: { damping: 14, stiffness: 120 } });
  const translateY = interpolate(progress, [0, 1], [80, 0]);
  return <AbsoluteFill style={withTransform(`translateY(${translateY}px)`, progress)}>{children}</AbsoluteFill>;
};

export const SlideDownEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 18);
  const translateY = interpolate(progress, [0, 1], [-80, 0]);
  return <AbsoluteFill style={withTransform(`translateY(${translateY}px)`, progress)}>{children}</AbsoluteFill>;
};

export const SlideLeftEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 18);
  const translateX = interpolate(progress, [0, 1], [180, 0]);
  return <AbsoluteFill style={withTransform(`translateX(${translateX}px)`, progress)}>{children}</AbsoluteFill>;
};

export const SlideRightEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 18);
  const translateX = interpolate(progress, [0, 1], [-180, 0]);
  return <AbsoluteFill style={withTransform(`translateX(${translateX}px)`, progress)}>{children}</AbsoluteFill>;
};

export const ZoomInEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 16);
  const scale = interpolate(progress, [0, 1], [0.75, 1]);
  return <AbsoluteFill style={withTransform(`scale(${scale})`, progress)}>{children}</AbsoluteFill>;
};

export const ZoomSpinEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 20);
  const scale = interpolate(progress, [0, 1], [0.35, 1]);
  const rotate = interpolate(progress, [0, 1], [-10, 0]);
  return <AbsoluteFill style={withTransform(`scale(${scale}) rotate(${rotate}deg)`, progress)}>{children}</AbsoluteFill>;
};

export const PulseEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 14);
  const scale = interpolate(progress, [0, 0.6, 1], [1.12, 0.95, 1]);
  return <AbsoluteFill style={withTransform(`scale(${scale})`, progress)}>{children}</AbsoluteFill>;
};

export const FadeEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 12);
  return <AbsoluteFill style={withTransform('none', progress)}>{children}</AbsoluteFill>;
};

export const FlipEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 18);
  const rotateY = interpolate(progress, [0, 1], [-90, 0]);
  return (
    <AbsoluteFill style={{ perspective: 1000 }}>
      <AbsoluteFill style={withTransform(`rotateY(${rotateY}deg)`, progress)}>{children}</AbsoluteFill>
    </AbsoluteFill>
  );
};

export const BounceEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const progress = getNormalizedProgress(frame, effectFrames ?? 20);
  const translateY = interpolate(progress, [0, 0.6, 0.8, 1], [120, -20, 10, 0]);
  return <AbsoluteFill style={withTransform(`translateY(${translateY}px)`, progress)}>{children}</AbsoluteFill>;
};

export const MeteoriteEntrance: FC<EffectComponentProps> = ({ children, effectFrames }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const dur = effectFrames ?? 24;

  const approach = interpolate(frame, [0, dur * 0.35], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const impact = spring({ frame: Math.max(0, frame - dur * 0.35), fps, durationInFrames: dur * 0.65, config: { damping: 8, stiffness: 250, mass: 0.6 } });
  const phase = approach < 1 ? approach : 1;
  const settled = approach >= 1 ? impact : 0;

  const translateX = interpolate(phase, [0, 1], [600, 0]);
  const translateY = interpolate(phase, [0, 1], [-500, 0]);
  const rotate = interpolate(phase, [0, 1], [-35, 0]);
  const preImpactScale = interpolate(phase, [0, 1], [0.15, 1]);

  const bounceScale = settled > 0 ? interpolate(settled, [0, 1], [1.2, 1]) : 1;
  const finalScale = preImpactScale * bounceScale;

  const shakeIntensity = interpolate(settled, [0, 0.15, 0.5, 1], [0, 12, 4, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const shakeX = shakeIntensity * Math.sin(frame * 47);
  const shakeY = shakeIntensity * Math.cos(frame * 31);

  const flashOpacity = interpolate(settled, [0, 0.08, 0.3], [0, 0.9, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const glowSize = interpolate(settled, [0, 0.5], [20, 80], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const glowOpacity = interpolate(settled, [0, 0.1, 0.6], [0, 0.7, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const brightness = interpolate(settled, [0, 0.1, 0.4], [1, 1.8, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const opacity = interpolate(phase, [0, 0.15], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  return (
    <AbsoluteFill style={{ transform: `translate(${shakeX}px, ${shakeY}px)` }}>
      <AbsoluteFill
        style={{
          background: `rgba(255, 240, 200, ${flashOpacity})`,
          pointerEvents: 'none',
          zIndex: 10,
        }}
      />
      <AbsoluteFill
        style={{
          background: `radial-gradient(circle at 50% 50%, rgba(255, 160, 40, ${glowOpacity}) 0%, rgba(255, 100, 20, ${glowOpacity * 0.5}) ${glowSize * 0.5}%, transparent ${glowSize}%)`,
          pointerEvents: 'none',
          zIndex: 5,
        }}
      />
      <AbsoluteFill
        style={{
          transform: `translate(${translateX}px, ${translateY}px) rotate(${rotate}deg) scale(${finalScale})`,
          opacity,
          filter: `brightness(${brightness})`,
        }}
      >
        {children}
      </AbsoluteFill>
    </AbsoluteFill>
  );
};

