import type { FC, ReactNode } from 'react';
import { secondsToFrames } from '@/tools/video-editor/lib/config-utils';
import { DynamicEffectRegistry } from '@/tools/video-editor/effects/DynamicEffectRegistry';
import { EffectErrorBoundary } from '@/tools/video-editor/effects/EffectErrorBoundary';
import { validateAndCoerceParams } from '@/tools/video-editor/effects/validateParams';
import {
  BounceEntrance,
  FadeEntrance,
  FlipEntrance,
  MeteoriteEntrance,
  PulseEntrance,
  SlideDownEntrance,
  SlideLeftEntrance,
  SlideRightEntrance,
  SlideUpEntrance,
  ZoomInEntrance,
  ZoomSpinEntrance,
  type EffectComponentProps,
} from '@/tools/video-editor/effects/entrances';
import {
  DriftEffect,
  FloatEffect,
  GlitchEffect,
  KenBurnsEffect,
  SlowZoomEffect,
} from '@/tools/video-editor/effects/continuous';
import {
  DissolveExit,
  FadeOutExit,
  FlipExit,
  ShrinkExit,
  SlideDownExit,
  ZoomOutExit,
} from '@/tools/video-editor/effects/exits';
import type { ParameterSchema, ResolvedTimelineClip } from '@/tools/video-editor/types';

export type ClipEffectComponent = FC<EffectComponentProps>;

export const entranceEffects: Record<string, ClipEffectComponent> = {
  'slide-up': SlideUpEntrance,
  'slide-down': SlideDownEntrance,
  'slide-left': SlideLeftEntrance,
  'slide-right': SlideRightEntrance,
  'zoom-in': ZoomInEntrance,
  'zoom-spin': ZoomSpinEntrance,
  pulse: PulseEntrance,
  fade: FadeEntrance,
  flip: FlipEntrance,
  bounce: BounceEntrance,
  meteorite: MeteoriteEntrance,
};

export const exitEffects: Record<string, ClipEffectComponent> = {
  'slide-down': SlideDownExit,
  'zoom-out': ZoomOutExit,
  flip: FlipExit,
  'fade-out': FadeOutExit,
  shrink: ShrinkExit,
  dissolve: DissolveExit,
};

export const continuousEffects: Record<string, ClipEffectComponent> = {
  'ken-burns': KenBurnsEffect,
  float: FloatEffect,
  glitch: GlitchEffect,
  'slow-zoom': SlowZoomEffect,
  drift: DriftEffect,
};

export const entranceEffectTypes = Object.keys(entranceEffects);
export const exitEffectTypes = Object.keys(exitEffects);
export const continuousEffectTypes = Object.keys(continuousEffects);

const allBuiltInEffects: Record<string, ClipEffectComponent> = {
  ...entranceEffects,
  ...exitEffects,
  ...continuousEffects,
};

let effectRegistry: DynamicEffectRegistry | null = null;

export function getEffectRegistry(): DynamicEffectRegistry {
  if (!effectRegistry) {
    effectRegistry = new DynamicEffectRegistry(allBuiltInEffects);
  }

  return effectRegistry;
}

export function replaceEffectRegistry(registry: DynamicEffectRegistry): DynamicEffectRegistry {
  effectRegistry = registry;
  return effectRegistry;
}

const resolveEffectName = (type: string): string => {
  return type.startsWith('custom:') ? type.slice(7) : type;
};

export const lookupEffect = (
  builtInMap: Record<string, ClipEffectComponent>,
  type: string,
): ClipEffectComponent | null => {
  const name = resolveEffectName(type);
  if (builtInMap[name]) {
    return builtInMap[name];
  }

  const registry = getEffectRegistry();
  return registry.get(name) ?? null;
};

type WrapWithEffectConfig = {
  effectName: string;
  durationInFrames: number;
  effectFrames?: number;
  intensity?: number;
  params?: Record<string, unknown>;
  schema?: ParameterSchema;
};

export const wrapWithEffect = (
  content: ReactNode,
  EffectComponent: ClipEffectComponent,
  { effectName, durationInFrames, effectFrames, intensity, params, schema }: WrapWithEffectConfig,
): ReactNode => {
  return (
    <EffectErrorBoundary effectName={effectName} fallback={content}>
      <EffectComponent
        durationInFrames={durationInFrames}
        effectFrames={effectFrames}
        intensity={intensity}
        params={validateAndCoerceParams(params, schema)}
      >
        {content}
      </EffectComponent>
    </EffectErrorBoundary>
  );
};

export const wrapWithClipEffects = (
  content: ReactNode,
  clip: ResolvedTimelineClip,
  durationInFrames: number,
  fps: number,
): ReactNode => {
  let wrapped = content;
  const registry = getEffectRegistry();

  const continuous = clip.continuous ? lookupEffect(continuousEffects, clip.continuous.type) : null;
  if (clip.continuous && !continuous) {
    console.warn('[EffectWrap] continuous effect NOT FOUND for clip=%s type=%s', clip.id, clip.continuous.type);
  }
  if (continuous) {
    wrapped = wrapWithEffect(wrapped, continuous, {
      effectName: clip.continuous.type,
      durationInFrames,
      effectFrames: durationInFrames,
      intensity: clip.continuous.intensity ?? 0.5,
      params: clip.continuous.params,
      schema: registry.getSchema(clip.continuous.type),
    });
  }

  const entrance = clip.entrance ? lookupEffect(entranceEffects, clip.entrance.type) : null;
  if (entrance) {
    wrapped = wrapWithEffect(wrapped, entrance, {
      effectName: clip.entrance.type,
      durationInFrames,
      effectFrames: secondsToFrames(clip.entrance.duration ?? 0.4, fps),
      intensity: clip.entrance.intensity,
      params: clip.entrance.params,
      schema: registry.getSchema(clip.entrance.type),
    });
  }

  const exit = clip.exit ? lookupEffect(exitEffects, clip.exit.type) : null;
  if (exit) {
    wrapped = wrapWithEffect(wrapped, exit, {
      effectName: clip.exit.type,
      durationInFrames,
      effectFrames: secondsToFrames(clip.exit.duration ?? 0.4, fps),
      intensity: clip.exit.intensity,
      params: clip.exit.params,
      schema: registry.getSchema(clip.exit.type),
    });
  }

  return wrapped;
};

import type { FC } from 'react';
import type { EffectComponentProps } from '@/tools/video-editor/effects/entrances';
import { compileEffect, compileEffectAsync } from '@/tools/video-editor/effects/compileEffect';
import type { ParameterSchema } from '@/tools/video-editor/types';

type DynamicEffectRecord = {
  component: FC<EffectComponentProps>;
  code: string;
  schema?: ParameterSchema;
};

export class DynamicEffectRegistry {
  private builtIn: Record<string, FC<EffectComponentProps>>;
  private dynamic: Record<string, DynamicEffectRecord> = {};
  private pendingAsync: Record<string, { code: string; schema?: ParameterSchema }> = {};
  private _version = 0;
  private _batchDepth = 0;
  private _pendingNotify = false;
  private _listeners = new Set<() => void>();

  constructor(builtIn: Record<string, FC<EffectComponentProps>>) {
    this.builtIn = { ...builtIn };
  }

  subscribe = (listener: () => void): (() => void) => {
    this._listeners.add(listener);
    return () => this._listeners.delete(listener);
  };

  getSnapshot = (): number => this._version;

  async batch(fn: () => void | Promise<void>): Promise<void> {
    this._batchDepth += 1;
    try {
      await fn();
    } finally {
      this._batchDepth -= 1;
      if (this._batchDepth === 0 && this._pendingNotify) {
        this._pendingNotify = false;
        this._notify();
      }
    }
  }

  register(name: string, code: string, schema?: ParameterSchema): void {
    const normalized = this.normalizeName(name);
    const existing = this.dynamic[normalized];
    if (existing?.code === code && existing.schema === schema) return;
    delete this.pendingAsync[normalized];
    const component = compileEffect(code);
    this.dynamic[normalized] = { component, code, schema };
    this._notify();
  }

  async registerAsync(name: string, code: string, schema?: ParameterSchema): Promise<void> {
    const normalized = this.normalizeName(name);
    const existing = this.dynamic[normalized];
    if (existing?.code === code && existing.schema === schema) return;
    this.pendingAsync[normalized] = { code, schema };
    const component = await compileEffectAsync(code);
    const pending = this.pendingAsync[normalized];
    if (!pending || pending.code !== code || pending.schema !== schema) return;
    delete this.pendingAsync[normalized];
    this.dynamic[normalized] = { component, code, schema };
    this._notify();
  }

  unregister(name: string): void {
    const normalized = this.normalizeName(name);
    if (!(normalized in this.dynamic)) return;
    delete this.pendingAsync[normalized];
    delete this.dynamic[normalized];
    this._notify();
  }

  get(name: string): FC<EffectComponentProps> | undefined {
    const normalized = this.normalizeName(name);
    return this.builtIn[normalized] ?? this.dynamic[normalized]?.component;
  }

  getCode(name: string): string | undefined {
    return this.dynamic[this.normalizeName(name)]?.code;
  }

  getSchema(name: string): ParameterSchema | undefined {
    return this.dynamic[this.normalizeName(name)]?.schema;
  }

  listAll(): string[] {
    return [...new Set([...Object.keys(this.builtIn), ...Object.keys(this.dynamic)])];
  }

  isDynamic(name: string): boolean {
    const normalized = this.normalizeName(name);
    return normalized in this.dynamic && !(normalized in this.builtIn);
  }

  getAllDynamicCode(): Record<string, string> {
    return Object.fromEntries(
      Object.entries(this.dynamic).map(([name, { code }]) => [name, code]),
    );
  }

  private _notify(): void {
    if (this._batchDepth > 0) {
      this._pendingNotify = true;
      return;
    }
    this._version += 1;
    this._listeners.forEach((listener) => listener());
  }

  private normalizeName(name: string): string {
    return name.startsWith('custom:') ? name.slice(7) : name;
  }
}

import { Component, type ReactNode } from 'react';

type EffectErrorBoundaryProps = { effectName: string; fallback: ReactNode; children: ReactNode };
type EffectErrorBoundaryState = { hasError: boolean };

export class EffectErrorBoundary extends Component<EffectErrorBoundaryProps, EffectErrorBoundaryState> {
  state: EffectErrorBoundaryState = { hasError: false };

  static getDerivedStateFromError(): EffectErrorBoundaryState {
    return { hasError: true };
  }

  componentDidCatch(error: Error) {
    console.error(`[EffectErrorBoundary] "${this.props.effectName}" runtime error: ${error.message}`);
  }

  componentDidUpdate(prevProps: EffectErrorBoundaryProps) {
    if (this.state.hasError && prevProps.effectName !== this.props.effectName) this.setState({ hasError: false });
  }

  render() {
    return this.state.hasError ? this.props.fallback : this.props.children;
  }
}

